mapper.select:
SELECT id, product_id, seckill_activity_id, total_stock, sold_stock, remaining_stock, create_time, update_time
FROM inventory
WHERE seckill_activity_id = #{seckillActivityId}

mapper.update:
UPDATE inventory
SET total_stock = #{totalStock},
    sold_stock = #{soldStock},
    remaining_stock = #{remainingStock},
    update_time = #{updateTime}
WHERE seckill_activity_id = #{seckillActivityId}

UPDATE inventory
SET sold_stock = sold_stock + #{quantity},
    remaining_stock = remaining_stock - #{quantity},
    update_time = #{updateTime}
WHERE seckill_activity_id = #{seckillActivityId}
  AND remaining_stock = #{expectedRemainingStock}
  AND remaining_stock >= #{quantity}
